130→    fn write_creates_parent_dirs() {
131→        let mut m = Manifest::new();
132→        m.apply_write(
133→            "/a/b/c.txt".to_string(),
134→            BlobHash::from_hex("abc"),
135→            10,
136→            None,
137→            1000,
138→        );
139→        assert!(m.exists("/a"));
140→        assert!(m.exists("/a/b"));
141→        assert!(m.exists("/a/b/c.txt"));
142→    }
143→
144→    #[test]
145→    fn delete_removes_entry() {
146→        let mut m = Manifest::new();
147→        m.apply_write(
