179→        m.apply_write("/src/b.rs".to_string(), BlobHash::from_hex("b"), 2, None, 2);
180→        m.apply_write("/doc/c.md".to_string(), BlobHash::from_hex("c"), 3, None, 3);
181→
182→        let src_entries = m.list("/src/");
183→        assert_eq!(src_entries.len(), 2);
184→    }
185→
186→    #[test]
187→    fn empty_manifest() {
