  1→use std::fs;
  2→use std::path::Path;
  3→use walkdir::WalkDir;
  4→
  5→use crate::manifest::Manifest;
  6→use lago_core::LagoResult;
  7→use lago_store::BlobStore;
  8→
  9→/// Builds a new manifest by scanning a physical directory.
 10→///
 11→/// Uses the `previous_manifest` to optimize hashing. If a file's size and
 12→/// last modified time (mtime) match the previous entry, its hash is reused
 13→/// instead of recalculating and re-storing the blob.
 14→pub fn snapshot(
 15→    root: &Path,
 16→    previous_manifest: &Manifest,
 17→    blob_store: &BlobStore,
 18→) -> LagoResult<Manifest> {
 19→    let mut new_manifest = Manifest::new();
 20→
 21→    // Prune entire directory trees early so WalkDir never descends into them.
 22→    let walker = WalkDir::new(root).into_iter().filter_entry(|entry| {
 23→        let name = entry.file_name().to_string_lossy();
 24→        !matches!(
 25→            name.as_ref(),
 26→            ".git"
 27→                | ".lago"
 28→                | ".lake"
 29→                | ".arcan"
 30→                | ".target"
 31→                | "target"
 32→                | "node_modules"
 33→                | ".DS_Store"
 34→        )
 35→    });
 36→
 37→    for entry in walker.filter_map(Result::ok) {
 38→        let path = entry.path();
 39→
 40→        // Ignore symlinks and directories in this pass
 41→        if !path.is_file() {
 42→            continue;
 43→        }
 44→
 45→        let rel_path = path.strip_prefix(root).unwrap_or(path);
 46→        let rel_str = rel_path.to_string_lossy().to_string();
 47→
 48→        let virtual_path = format!("/{}", rel_str);
 49→
 50→        let metadata = fs::metadata(path)?;
 51→        let size = metadata.len();
 52→        let mtime = metadata
 53→            .modified()
 54→            .unwrap_or_else(|_| std::time::SystemTime::now())
 55→            .duration_since(std::time::UNIX_EPOCH)
 56→            .unwrap_or_default()
 57→            .as_secs();
 58→
 59→        // Check if we can reuse the previous hash (fast path)
 60→        let mut reused = false;
 61→        if let Some(prev_entry) = previous_manifest.get(&virtual_path) {
 62→            if prev_entry.size_bytes == size && prev_entry.updated_at == mtime {
 63→                // Match: assume content is identical to skip IO + hashing
 64→                new_manifest.apply_write(
 65→                    virtual_path.clone(),
 66→                    prev_entry.blob_hash.clone(),
 67→                    size,
 68→                    prev_entry.content_type.clone(),
 69→                    mtime,
 70→                );
 71→                reused = true;
 72→            }
 73→        }
 74→
 75→        if !reused {
 76→            // Slow path: Read file, hash, and store in the blob store
 77→            let data = fs::read(path)?;
 78→            let new_hash = blob_store.put(&data)?;
 79→
 80→            new_manifest.apply_write(
 81→                virtual_path,
 82→                // The blob store returns a lego_core::BlobHash
 83→                lago_core::BlobHash::from_hex(new_hash.as_str()),
 84→                size,
 85→                None,
 86→                mtime,
 87→            );
 88→        }
 89→    }
 90→
 91→    Ok(new_manifest)
 92→}
 93→
 94→#[cfg(test)]
 95→mod tests {
 96→    use super::*;
 97→    use std::io::Write;
 98→
 99→    #[test]
100→    fn snapshot_creates_new_manifest() {
101→        let temp = tempfile::tempdir().unwrap();
102→        let blob_store = BlobStore::open(temp.path().join("blobs")).unwrap();
103→        let workspace = temp.path().join("ws");
104→        fs::create_dir_all(&workspace).unwrap();
105→
106→        // Write a file to real disk
107→        let file_path = workspace.join("hello.txt");
108→        let mut file = fs::File::create(&file_path).unwrap();
109→        file.write_all(b"world").unwrap();
110→        file.sync_all().unwrap();
111→
112→        let prev = Manifest::new();
113→        let next = snapshot(&workspace, &prev, &blob_store).unwrap();
114→
115→        assert!(next.exists("/hello.txt"));
116→        let entry = next.get("/hello.txt").unwrap();
117→        assert_eq!(entry.size_bytes, 5);
118→        assert!(blob_store.exists(&entry.blob_hash));
119→    }
120→
121→    #[test]
122→    fn snapshot_reuses_unchanged_files() {
123→        let temp = tempfile::tempdir().unwrap();
124→        let blob_store = BlobStore::open(temp.path().join("blobs")).unwrap();
125→        let workspace = temp.path().join("ws");
126→        fs::create_dir_all(&workspace).unwrap();
127→
128→        let file_path = workspace.join("hello.txt");
129→        fs::write(&file_path, "world").unwrap();
130→
131→        let prev = snapshot(&workspace, &Manifest::new(), &blob_store).unwrap();
132→
133→        let prev_entry = prev.get("/hello.txt").unwrap().clone();
134→
135→        // Take snapshot again without changes
136→        let next = snapshot(&workspace, &prev, &blob_store).unwrap();
137→        let next_entry = next.get("/hello.txt").unwrap();
138→
139→        assert_eq!(prev_entry.blob_hash, next_entry.blob_hash);
140→        assert_eq!(prev_entry.updated_at, next_entry.updated_at);
141→    }
142→}
