 783→fn run_login(provider: &str, device: bool, data_dir: &Path) -> anyhow::Result<()> {
 784→    // Normalize to canonical provider name for config persistence.
 785→    let canonical = match provider {
 786→        "codex" | "openai-codex" => "openai",
 787→        other => other,
 788→    };
 789→
 790→    match provider {
 791→        "openai" | "codex" | "openai-codex" => {
 792→            if device {
 793→                arcan_provider::oauth::device_login_openai().map_err(|e| anyhow::anyhow!("{e}"))?;
 794→            } else {
 795→                arcan_provider::oauth::pkce_login_openai().map_err(|e| anyhow::anyhow!("{e}"))?;
 796→            }
 797→        }
 798→        _ => {
 799→            return Err(anyhow::anyhow!(
 800→                "Unknown provider '{provider}'. Supported: openai"
 801→            ));
 802→        }
 803→    }
 804→
 805→    // Set the provider as the new default after successful login.
 806→    let mut file_config = config::load_config(data_dir);
 807→    file_config.set_key("provider", canonical).ok();
 808→    config::save_config(data_dir, &file_config)?;
 809→    eprintln!("Default provider set to '{canonical}'");
 810→
 811→    Ok(())
 812→}
