 866→fn run_logout(provider: &str, data_dir: &Path) -> anyhow::Result<()> {
 867→    // Normalize provider name for credential lookup.
 868→    let normalized = match provider {
 869→        "codex" | "openai-codex" => "openai",
 870→        other => other,
 871→    };
 872→    arcan_provider::oauth::remove_tokens(normalized).map_err(|e| anyhow::anyhow!("{e}"))?;
 873→
 874→    // Clear the default provider if it matches the one being logged out.
 875→    let mut file_config = config::load_config(data_dir);
 876→    if file_config.defaults.provider.as_deref() == Some(normalized) {
 877→        file_config.defaults.provider = None;
 878→        config::save_config(data_dir, &file_config)?;
 879→        eprintln!("Default provider cleared");
 880→    }
 881→
 882→    eprintln!("Logged out of {provider}");
 883→    Ok(())
 884→}
