  1→use lago_core::{BlobHash, ManifestEntry};
  2→use serde::{Deserialize, Serialize};
  3→use std::collections::BTreeMap;
  4→
  5→use crate::tree::parent_dirs;
  6→
  7→/// A versioned filesystem manifest mapping paths to file entries.
  8→///
  9→/// The manifest is the core data structure of lago-fs. It tracks every file
 10→/// in the virtual filesystem as a `ManifestEntry` keyed by its path string.
 11→/// Parent directories are implicitly created when files are written.
 12→#[derive(Debug, Clone, Default, Serialize, Deserialize)]
 13→pub struct Manifest {
 14→    entries: BTreeMap<String, ManifestEntry>,
 15→}
 16→
 17→impl Manifest {
 18→    /// Create a new empty manifest.
 19→    pub fn new() -> Self {
 20→        Self {
 21→            entries: BTreeMap::new(),
 22→        }
 23→    }
 24→
 25→    /// Insert or update a file entry. Implicitly creates parent directory
 26→    /// entries (as zero-size sentinel entries) if they do not already exist.
 27→    pub fn apply_write(
 28→        &mut self,
 29→        path: String,
 30→        blob_hash: BlobHash,
 31→        size_bytes: u64,
 32→        content_type: Option<String>,
 33→        timestamp: u64,
 34→    ) {
 35→        // Ensure all parent directories exist as implicit entries
 36→        for dir in parent_dirs(&path) {
 37→            if !self.entries.contains_key(&dir) {
 38→                self.entries.insert(
 39→                    dir.clone(),
 40→                    ManifestEntry {
 41→                        path: dir,
 42→                        blob_hash: BlobHash::from_hex(""),
 43→                        size_bytes: 0,
 44→                        content_type: Some("inode/directory".to_string()),
 45→                        updated_at: timestamp,
 46→                    },
 47→                );
 48→            }
 49→        }
 50→
 51→        let entry = ManifestEntry {
 52→            path: path.clone(),
 53→            blob_hash,
 54→            size_bytes,
 55→            content_type,
 56→            updated_at: timestamp,
 57→        };
 58→        self.entries.insert(path, entry);
 59→    }
 60→
 61→    /// Remove a file entry from the manifest.
 62→    pub fn apply_delete(&mut self, path: &str) {
 63→        self.entries.remove(path);
 64→    }
 65→
 66→    /// Move an entry from `old_path` to `new_path`.
 67→    /// If the old entry does not exist, this is a no-op.
 68→    pub fn apply_rename(&mut self, old_path: &str, new_path: String) {
 69→        if let Some(mut entry) = self.entries.remove(old_path) {
 70→            entry.path = new_path.clone();
 71→            self.entries.insert(new_path, entry);
 72→        }
 73→    }
 74→
 75→    /// Look up a single entry by exact path.
 76→    pub fn get(&self, path: &str) -> Option<&ManifestEntry> {
 77→        self.entries.get(path)
 78→    }
 79→
 80→    /// List all entries whose path starts with the given prefix.
 81→    pub fn list(&self, prefix: &str) -> Vec<&ManifestEntry> {
 82→        self.entries
 83→            .range(prefix.to_string()..)
 84→            .take_while(|(k, _)| k.starts_with(prefix))
 85→            .map(|(_, v)| v)
 86→            .collect()
 87→    }
 88→
 89→    /// Check whether a path exists in the manifest.
 90→    pub fn exists(&self, path: &str) -> bool {
 91→        self.entries.contains_key(path)
